//! Echo framework recognizer (Go).
//!
//! Detects Echo apps by import path and extracts route, middleware, group, and
//! listen registrations.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

pub struct EchoRecognizer;

impl FrameworkRecognizer for EchoRecognizer {
    fn framework_id(&self) -> &str {
        "echo"
    }

    fn language(&self) -> &str {
        "go"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        if !source.contains("\"github.com/labstack/echo/v4\"") {
            return None;
        }

        let mut prefixes = detect_echo_prefixes(source);
        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut middleware_order = 0;

        for line in source.lines() {
            let trimmed = line.trim();

            if let Some((name, parent, prefix)) = parse_group_assignment(trimmed, ".Group(") {
                let parent_prefix = prefixes.get(parent.as_str()).cloned().unwrap_or_default();
                prefixes.insert(name, join_paths(&parent_prefix, &prefix));
            }

            for (name, prefix) in &prefixes {
                for (method_name, method) in &[
                    ("GET", HttpMethod::Get),
                    ("POST", HttpMethod::Post),
                    ("PUT", HttpMethod::Put),
                    ("DELETE", HttpMethod::Delete),
                    ("PATCH", HttpMethod::Patch),
                    ("Any", HttpMethod::All),
                ] {
                    let pattern = format!("{}.{}(", name, method_name);
                    if let Some(start) = trimmed.find(&pattern) {
                        let after_paren = start + pattern.len();
                        if let Some(route_path) = extract_string_arg(&trimmed[after_paren..]) {
                            let path = join_paths(prefix, &route_path);
                            let handler_name = extract_go_handler(&trimmed[after_paren..])
                                .unwrap_or_else(|| {
                                    format!(
                                        "{}_{}",
                                        method_name.to_lowercase(),
                                        sanitize_path(&path)
                                    )
                                });
                            let handler_cfg_index = cfgs
                                .iter()
                                .position(|cfg| cfg.function_name == handler_name);

                            routes.push(Route {
                                method: method.clone(),
                                path,
                                handler_name,
                                handler_cfg_index,
                                source_start: 0,
                                source_end: 0,
                            });
                        }
                    }
                }

                let use_pattern = format!("{}.Use(", name);
                if let Some(start) = trimmed.find(&use_pattern) {
                    let rest = &trimmed[start + use_pattern.len()..];
                    let middleware_name: String = rest
                        .chars()
                        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
                        .collect();
                    if !middleware_name.is_empty() {
                        middleware.push(Middleware {
                            name: middleware_name,
                            path_prefix: Some(prefix.clone()),
                            handler_cfg_index: None,
                            order: middleware_order,
                        });
                        middleware_order += 1;
                    }
                }
            }
        }

        if routes.is_empty() {
            return None;
        }

        Some(FrameworkTopology {
            framework: "echo".to_string(),
            language: "go".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port: detect_echo_port(source, &prefixes),
            config: HashMap::new(),
        })
    }
}

fn detect_echo_prefixes(source: &str) -> HashMap<String, String> {
    let mut prefixes = HashMap::new();

    for line in source.lines() {
        let trimmed = line.trim();
        if trimmed.contains("echo.New()") {
            if let Some(name) = trimmed
                .split(":=")
                .next()
                .map(|candidate| candidate.trim().to_string())
            {
                if !name.is_empty() {
                    prefixes.insert(name, "/".to_string());
                }
            }
        }
    }

    if prefixes.is_empty() {
        prefixes.insert("e".to_string(), "/".to_string());
    }

    prefixes
}

fn parse_group_assignment(line: &str, marker: &str) -> Option<(String, String, String)> {
    let group_index = line.find(marker)?;
    let name = line.split(":=").next()?.trim().to_string();
    let parent = line[..group_index].split(":=").nth(1)?.trim().to_string();
    let prefix = extract_string_arg(&line[group_index + marker.len()..])?;
    Some((name, parent, prefix))
}

fn extract_go_handler(s: &str) -> Option<String> {
    let after_path = s.find(',')? + 1;
    let rest = s[after_path..].trim();
    if rest.starts_with("func(") || rest.starts_with("func (") {
        return None;
    }

    let name: String = rest
        .chars()
        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
        .collect();

    if name.is_empty() {
        None
    } else {
        Some(name)
    }
}

fn extract_string_arg(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.chars().next()?;
    if quote != '"' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find('"')?;
    Some(rest[..end].to_string())
}

fn detect_echo_port(source: &str, prefixes: &HashMap<String, String>) -> Option<u16> {
    for line in source.lines() {
        let trimmed = line.trim();
        for name in prefixes.keys() {
            let pattern = format!("{}.Start(", name);
            if let Some(start) = trimmed.find(&pattern) {
                let addr = extract_string_arg(&trimmed[start + pattern.len()..])?;
                if let Some(port) = addr
                    .rsplit(':')
                    .next()
                    .and_then(|value| value.parse::<u16>().ok())
                {
                    return Some(port);
                }
            }
        }
    }
    None
}

fn normalize_path(value: &str) -> String {
    if value.is_empty() {
        return "/".to_string();
    }
    if value.starts_with('/') {
        value.to_string()
    } else {
        format!("/{value}")
    }
}

fn join_paths(prefix: &str, child: &str) -> String {
    let normalized_prefix = normalize_path(prefix).trim_end_matches('/').to_string();
    let normalized_child = normalize_path(child);
    if normalized_prefix == "/" {
        return normalized_child;
    }
    if normalized_child == "/" {
        return normalized_prefix;
    }
    format!("{}{}", normalized_prefix, normalized_child)
}

fn sanitize_path(path: &str) -> String {
    path.chars()
        .map(|c| if c.is_alphanumeric() { c } else { '_' })
        .collect::<String>()
        .trim_matches('_')
        .to_string()
}
